// socket.ts (module singleton)
let socket: WebSocket | null = null;
export function getSocket() {
  if (!socket) socket = new WebSocket(URL);
  return socket;
}

export function useSocketEvent<T>(event: string, handler: (msg: T) => void) {
  useEffect(() => {
    const sock = getSocket();
    const fn = (e: MessageEvent) => handler(JSON.parse(e.data));
    sock.addEventListener(event, fn);
    return () => sock.removeEventListener(event, fn);
  }, [event, handler]);
}

