async function callWithBackoff<T>(fn: () => Promise<T>, max = 5) {
  let delay = 250;
  for (let i = 0; i < max; i++) {
    try { return await fn(); }
    catch (e: any) {
      if (e.status !== 429 || i === max - 1) throw e;
      await new Promise((r) => setTimeout(r, delay + Math.random() * 250));
      delay *= 2;
    }
  }
  throw new Error('unreachable');
}

